// The ensures of `det_init2zero` is an *implication*:
//     (LHS-conjunction-of-foralls-and-wfs) ==> det_init2zero_equal(...).
// The previous attempt's bare
//     assert(forall|index: int| ... post1_self_@[index] == 0);
// failed because that `forall` is on the LHS of the implication, not a
// hypothesis at the prelude point.
//
// We introduce the LHS via a ghost `if` whose condition is exactly that
// LHS conjunction; inside the `if` branch each conjunct (including the
// two zero-foralls) becomes a hypothesis, so we can line their disjoint
// triggers `post1_self_@[index]` / `post2_self_@[index]` up pointwise
// and close with Seq extensional equality.
if ((forall|index: int| 0 <= index < N ==> #[trigger] post1_self_@[index] == 0)
    && post1_self_.wf()
    && (forall|index: int| 0 <= index < N ==> #[trigger] post2_self_@[index] == 0)
    && post2_self_.wf())
{
    // Pointwise: for every in-range i, both arrays carry value 0.
    // The two explicit indexings below fire the two foralls' triggers
    // (`post1_self_@[i]` and `post2_self_@[i]`) at the same `i`.
    assert forall|i: int| 0 <= i < N implies post1_self_@[i] == post2_self_@[i] by {
        assert(post1_self_@[i] == 0);
        assert(post2_self_@[i] == 0);
    }

    // Both views have length N from `wf()`; matching lengths + pointwise
    // equality is exactly Seq extensional equality (`=~=`), which Verus
    // upgrades to plain `==` on Seq.
    assert(post1_self_@.len() == N);
    assert(post2_self_@.len() == N);
    assert(post1_self_@ =~= post2_self_@);
}
